1	const PROCESSING_FEE = 5;
2	
3	interface QuoteStep {
4	  op: "quote";
5	  items: { type: string }[];
6	}
7	
8	interface Scenario {
9	  customer: { yearsWithMHPCO: number };
10	  steps: QuoteStep[];
11	}
12	
13	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
14	  const results = scenario.steps.map((step) => {
15	    const policyBase = step.items.reduce((sum, item) => {
16	      if (item.type === "sword") return sum + 100;
17	      return sum;
18	    }, 0);
19	    const firstInsurance = policyBase * 0.1;
20	    const premium = Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
21	    return { premium };
22	  });
23	  return { results };
24	};
25

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge case: empty policy ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const { results } = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(results).toEqual([{ premium: 5 }]);
12	  });
13	
14	  // --- Base premiums for main items (single item, newcomer 0 yrs, first insurance) ---
15	  // These verify the base price list. Newcomer first insurance adds 10%; +5 fee.
16	  // To keep early tests focused on the base, we use a customer where modifiers cancel
17	  // or are explicitly accounted for in the description.
18	
19	  it("single sword, base premium 100 G → premium with first-insurance 10% + fee = 115 G", () => {
20	    const { results } = runScenario({
21	      customer: { yearsWithMHPCO: 0 },
22	      steps: [
23	        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] },
24	      ],
25	    });
26	    expect(results).toEqual([{ premium: 115 }]);
27	  });
28	  it.todo("single amulet, base premium 60 G → premium 71 G (60 +6 first +5 fee)");
29	  it.todo("single staff, base premium 80 G → premium 93 G (80 +8 first +5 fee)");
30	  it.todo("single potion, base premium 40 G → premium 49 G (40 +4 first +5 fee)");
31	
32	  // --- Components: 250 G value / 25 G base premium each ---
33	  it.todo("single rune, base premium 25 G → premium 32.5 rounded up 33 G (25 +2.5 first +5 fee)");
34	  it.todo("single moonstone, base premium 25 G → premium 33 G");
35	
36	  // --- Building block of 3 alike components ---
37	  it.todo("2 runes → 50 G base premium");
38	  it.todo("3 runes → 60 G base premium (block applies)");
39	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
40	  it.todo("7 runes → 175 G base premium (one block of 3 = 60, plus 4 singles = 100)");
41	
42	  // --- 'Alike' = same type ---
43	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
44	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
45	
46	  // --- Premium modifiers in isolation ---
47	  it.todo("cursed sword (newcomer, ench 3): 100 base +50 curse +10 first +5 fee = 165 G");
48	  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies (+30%)");
49	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
50	  it.todo("customer with exactly 2 years → 20% loyalty discount applies");
51	
52	  // --- Modifier scope on multi-item policies ---
53	  it.todo("cursed sword (base 100) + plain amulet (base 60): policy base 160, curse adds 50 (50% of cursed item base) → 210 before further modifiers and fee");
54	
55	  // --- Rounding ---
56	  it.todo("premium calculation yielding 197.5 G → 198 G (rounded up)");
57	  it.todo("payout calculation yielding 350.5 G → 350 G (rounded down)");
58	
59	  // --- Claim: standard reimbursement ---
60	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
61	  it.todo("damage to a rune (value 250), damage 200 → payout 100 (full minus 100 deductible)");
62	
63	  // --- Claim: enchantment threshold ---
64	  it.todo("steel sword, ench 9, damage 1000 → payout 400 (50% then deductible: 500-100)");
65	  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon full reimburse, then deductible)");
66	  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (50% wins, then deductible)");
67	  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (high-ench clause then deductible)");
68	
69	  // --- Claim: deductible per damage event ---
70	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");
71	
72	  // --- Claim: cap ---
73	  it.todo("policy covers sword + amulet → insurance sum 1600, cap 3200");
74	  it.todo("cursed sword (value 1000, premium 165) → cap 2000 (based on unmodified value)");
75	  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 (block affects premium only, not sum)");
76	  it.todo("two swords → insurance sum 2000, cap 4000");
77	
78	  // --- Claim: cap exhaustion across successive claims ---
79	  it.todo("sword (sum 1000, cap 2000); claim 1500 → payout 1400, remainingCap 600");
80	  it.todo("then second claim 1500 → payout 600, remainingCap 0 (reduced to remaining cap)");
81	
82	  // --- Multiple items of same type in damages ---
83	  it.todo("two swords insured; damages has two sword entries → each is a separate damage with own deductible");
84	  it.todo("damages has more entries of a type than insured (two sword damages, one sword) → CLI non-zero exit, claim rejected");
85	
86	  // --- Edge cases (CLI errors) ---
87	  it.todo("quote with unknown item type (broomstick) → CLI non-zero exit, error to stderr, no results on stdout");
88	  it.todo("claim references item not in policy (amulet damaged, only sword insured) → CLI non-zero exit, error to stderr");
89	  it.todo("claim damage with amount -200 → CLI non-zero exit, error to stderr");
90	
91	  // --- Integration examples ---
92	  it.todo("newcomer cursed sword (steel ench 3): premium 165 G");
93	  it.todo("long-standing (3 yrs) second contract, cursed sword (steel ench 7): premium 160 G");
94	
95	  // --- CLI end-to-end (schema example) ---
96	  it.todo("CLI: scenario with quote + claim returns results array of matching length and shape");
97	});
